reader := bufio.NewReader(os.Stdin)

var texto, antiga, nova string

fmt.Fscanln(reader, &texto)
fmt.Fscanln(reader, &antiga)
fmt.Fscanln(reader, &nova)

i := 0
for i < len(texto) {
	if i+len(antiga) <= len(texto) && texto[i:i+len(antiga)] == antiga {
		fmt.Print(nova)
		i += len(antiga)
	} else {
		fmt.Printf("%c", texto[i])
		i++
	}
}
fmt.Println()
